    if not user_role or user_role ~= "admin" then
        ngx.status = ngx.HTTP_FORBIDDEN
        ngx.say(cjson.encode({message = "Insufficient permissions"}))
        ngx.exit(ngx.HTTP_FORBIDDEN)
    end
end

local uri = ngx.var.uri
if not string.match(uri, "^/admin") and not string.match(uri, "^/api") then
